DROP TABLE IF EXISTS `ai_phone_list`;
CREATE TABLE `ai_phone_list` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `phone` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'ai客服号码',
  `ext_num` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '分机号',
  `user_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '绑定的用户账号',
  `start_date` datetime DEFAULT NULL COMMENT '有效期起',
  `end_date` datetime DEFAULT NULL COMMENT '有效期止',
  `ali_access_key_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '阿里云账号access_key_id',
  `ali_access_key_secret` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '阿里云账号access_key_secret',
  `ali_app_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '阿里云账号app_key',
  `ali_status` int DEFAULT NULL COMMENT '阿里云账号状态（1有效，0无效）',
  `coze-server-url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '智能体服务地址',
  `coze-bot-id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '机器人id',
  `coze-token` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '智能体token',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

