CREATE TABLE `cc_fs_modules_cat` (
  `id` int NOT NULL AUTO_INCREMENT,
  `cat_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- ----------------------------
-- Records of cc_fs_modules_cat
-- ----------------------------

-- ----------------------------
-- Table structure for cc_gateways
-- ----------------------------
DROP TABLE IF EXISTS `cc_gateways`;
CREATE TABLE `cc_gateways` (
  `id` int NOT NULL AUTO_INCREMENT,
  `gw_name` varchar(32) DEFAULT NULL COMMENT '网关名称',
  `profile_name` varchar(32) DEFAULT NULL COMMENT 'profile名称',
  `caller` varchar(3000) DEFAULT NULL COMMENT '外呼的主叫号码',
  `callee_prefix` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '被叫前缀;',
  `gw_addr` varchar(30) NOT NULL DEFAULT '' COMMENT '网关地址; ip地址:端口',
  `codec` varchar(10) NOT NULL DEFAULT 'pcma' COMMENT '外呼语音编码',
  `gw_desc` varchar(30) NOT NULL COMMENT '网关名称描述;',
  `max_concurrency` int NOT NULL DEFAULT '1' COMMENT '网关最大并发数; 仅用作手工选择参考，不用于程序判断：',
  `auth_username` varchar(50) DEFAULT '' COMMENT '注册模式下；认证用户名',
  `auth_password` varchar(50) DEFAULT '' COMMENT '注册模式下；认证密码',
  `priority` int NOT NULL COMMENT '使用优先级; 数字1-9； 数字越小，越优先被使用',
  `update_time` bigint NOT NULL COMMENT '网关信息更新时间',
  `register` int NOT NULL COMMENT '是否需要认证注册； 0 对接模式； 1注册模式',
  `configs` varchar(512) DEFAULT NULL COMMENT '自定义参数',
  `purpose` int DEFAULT '0' COMMENT '0 dropped; 1 phonebar; 2 outbound tasks; 3 Unlimited',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='外呼主叫号码表; ';

-- ----------------------------
-- Records of cc_gateways
-- ----------------------------

-- ----------------------------
-- Table structure for cc_inbound_black
-- ----------------------------
DROP TABLE IF EXISTS `cc_inbound_black`;
CREATE TABLE `cc_inbound_black` (
  `id` int NOT NULL AUTO_INCREMENT,
  `caller` varchar(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '黑名单主叫号码',
  `expired_time` bigint NOT NULL COMMENT '黑名单有效期',
  `add_time` bigint NOT NULL COMMENT '添加时间',
  `add_user` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '添加人',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- ----------------------------
-- Records of cc_inbound_black
-- ----------------------------

-- ----------------------------
-- Table structure for cc_inbound_cdr
-- ----------------------------
DROP TABLE IF EXISTS `cc_inbound_cdr`;
CREATE TABLE `cc_inbound_cdr` (
  `id` varchar(21) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `caller` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '主叫号码',
  `callee` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '被叫号码',
  `inbound_time` bigint NOT NULL COMMENT '呼入时间',
  `group_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '请求转接的坐席组',
  `answered_time` bigint NOT NULL DEFAULT '0' COMMENT '电话被接听时间',
  `manual_answered_time` bigint DEFAULT '0' COMMENT 'manual agent answered time.',
  `extnum` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '接听电话的分机号码',
  `opnum` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '接听电话的员工工号',
  `hangup_time` bigint NOT NULL DEFAULT '0' COMMENT '挂机时间',
  `answered_time_len` bigint NOT NULL DEFAULT '0' COMMENT '服务时长',
  `manual_answered_time_len` bigint NOT NULL DEFAULT '0' COMMENT 'The duration of the manual agent service time.',
  `time_len` bigint NOT NULL DEFAULT '0' COMMENT '通话总时长',
  `uuid` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '通话uuid',
  `wav_file` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '录音文件名',
  `chat_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '对话内容。',
  `asr_seconds` int NOT NULL DEFAULT '0' COMMENT 'asr时长（秒）',
  `tts_times` int NOT NULL DEFAULT '0' COMMENT 'tts调用次数（次）',
  `tts_flow_tokens` int NOT NULL DEFAULT '0' COMMENT '大模型tts的字符数（字符）',
  `input_tokens` int NOT NULL DEFAULT '0' COMMENT '总输入token数',
  `output_tokens` int NOT NULL DEFAULT '0' COMMENT '总输出token数',
  `total_cost` decimal(10,8) NOT NULL DEFAULT '0.00000000' COMMENT '总调用费用（asr+tts+大模型）',
  `billing_status` int NOT NULL DEFAULT '0' COMMENT '计费状态（1：已计费、0：未计费）',
  `ivr_dtmf_digits` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'customer dtmf input digits',
  `hangup_cause` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'hangup cause',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- ----------------------------
-- Records of cc_inbound_cdr
-- ----------------------------

-- ----------------------------
-- Table structure for cc_inbound_llm_account
-- ----------------------------
DROP TABLE IF EXISTS `cc_inbound_llm_account`;
CREATE TABLE `cc_inbound_llm_account` (
  `id` int NOT NULL AUTO_INCREMENT,
  `llm_account_id` int NOT NULL COMMENT 'llm or ai-agent account id.',
  `callee` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'callee number',
  `voice_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'TTS voice code for the robot',
  `voice_source` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'aliyun_tts' COMMENT 'tts provider',
  `service_type` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ai' COMMENT 'customer service mode: AI assistant or  ACD queue.  ai or acd or ivr',
  `asr_provider` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'aliyun' COMMENT 'asr提供者 （aliyun/doubao/microsoft）',
  `ai_transfer_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT 'way of transferring to manual:  acd、extension、gateway',
  `ai_transfer_data` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT 'Data of specific manual transfer methods',
  `ivr_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT 'IVR id',
  `satisf_survey_ivr_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'the IVR menu ID for satisfaction surveys',
  `inbound_alias` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'inbound alias',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- ----------------------------
-- Records of cc_inbound_llm_account
-- ----------------------------

-- ----------------------------
-- Table structure for cc_ivr
-- ----------------------------
DROP TABLE IF EXISTS `cc_ivr`;
CREATE TABLE `cc_ivr` (
  `id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `root_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '',
  `digit` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'DTMF digit key',
  `node_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'node name',
  `parent_node_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT 'id of parent node. ',
  `tts_text` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT 'the speech-to-text',
  `tts_text_wav` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'the wav audio file for tts_text',
  `action` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'acd、extension、hangup、gateway、play、playAndGetDigits、upaction、 function、ai ',
  `ai_transfer_data` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT 'Data of specific manual transfer methods',
  `wait_key_timeout` int NOT NULL COMMENT 'Wait for the key press timeout',
  `max_press_key_failures` int NOT NULL COMMENT 'The maximum number of attempts to press a key',
  `press_key_invalid_tips` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'press_key_invalid_tips',
  `press_key_invalid_tips_wav` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'the wav path for  press_key_invalid_tips',
  `failed_action` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'hangup、upaction',
  `digit_range` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '数字按键的可选范围',
  `enabled` smallint NOT NULL DEFAULT '1' COMMENT 'Whether to enable.',
  `tts_provider` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'tts_provider',
  `voice_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'name of tts speaker',
  `max_len` int DEFAULT '1' COMMENT 'max length of input digits',
  `min_len` int DEFAULT '1' COMMENT 'min length of input digits',
  `user_input_var_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'Variable name, store the value entered by the user to this variable.',
  `hangup_tips` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'hangup tips at current node.',
  `hangup_tips_wav` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'the wav path for  hangup tips.',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- ----------------------------
-- Records of cc_ivr
-- ----------------------------

-- ----------------------------
-- Table structure for cc_llm_agent_account
-- ----------------------------
DROP TABLE IF EXISTS `cc_llm_agent_account`;
CREATE TABLE `cc_llm_agent_account` (
  `id` int NOT NULL AUTO_INCREMENT,
  `account_json` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '账号详细信息',
  `provider_class_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'Name of the implementation class.',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '别名',
  `account_entity` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'Entity class for storing account config info.',
  `interrupt_flag` int DEFAULT '0' COMMENT '0：不打断，1：关键词打断，2：有声音就打断',
  `interrupt_keywords` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '打断关键词列表',
  `interrupt_ignore_keywords` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '打断忽略关键字列表',
  `intention_tips` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '客户意向提示词',
  `concurrent_num` int DEFAULT '1' COMMENT '模型并发数',
  `transfer_manual_digit` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '1' COMMENT 'A single-digit numeric code used to initiate the transfer to a human agent.',
  `kb_cat_id` int NOT NULL DEFAULT '-1' COMMENT 'kb_cat_id',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Conversation foundation:  configuration parameters for accessing large language models or ai agents.';

-- ----------------------------
-- Records of cc_llm_agent_account
-- ----------------------------

-- ----------------------------
-- Table structure for cc_llm_agent_provider
-- ----------------------------
DROP TABLE IF EXISTS `cc_llm_agent_provider`;
CREATE TABLE `cc_llm_agent_provider` (
  `id` int NOT NULL AUTO_INCREMENT,
  `provider_class_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `note` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- ----------------------------
-- Records of cc_llm_agent_provider
-- ----------------------------

