-- ----------------------------
-- Table structure for cc_outbound_cdr
-- ----------------------------
DROP TABLE IF EXISTS `cc_outbound_cdr`;
CREATE TABLE `cc_outbound_cdr` (
  `id` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `caller` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'caller',
  `opnum` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '工号',
  `callee` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'callee',
  `start_time` bigint NOT NULL COMMENT 'outbound call start time',
  `answered_time` bigint NOT NULL DEFAULT '0' COMMENT 'callee answerd time',
  `end_time` bigint NOT NULL COMMENT 'hangup time',
  `uuid` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'call uuid',
  `call_type` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'audio' COMMENT ' audio or  video',
  `time_len` int NOT NULL COMMENT 'duration of call session',
  `time_len_valid` int NOT NULL COMMENT 'duration of call session since callee answered.',
  `record_filename` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'record filename',
  `chat_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT 'Dialogue content',
  `hangup_cause` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'hangup cause',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci ROW_FORMAT=DYNAMIC COMMENT='call detail records for outbound calls.';

-- ----------------------------
-- Records of cc_outbound_cdr
-- ----------------------------

-- ----------------------------
-- Table structure for cc_params
-- ----------------------------
DROP TABLE IF EXISTS `cc_params`;
CREATE TABLE `cc_params` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `param_name` varchar(255) NOT NULL DEFAULT '',
  `param_code` varchar(100) NOT NULL,
  `param_value` varchar(2000) NOT NULL DEFAULT '',
  `param_type` varchar(50) NOT NULL DEFAULT '',
  `hide_value` int NOT NULL DEFAULT '0' COMMENT '是否隐藏显示敏感字段信息',
  `allow_edit` int NOT NULL DEFAULT '1',
  PRIMARY KEY (`id`),
  UNIQUE KEY `param_code` (`param_code`) USING BTREE
) ENGINE=MyISAM AUTO_INCREMENT=1231315 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- ----------------------------
-- Records of cc_params
-- ----------------------------

-- ----------------------------
-- Table structure for cc_tts_aliyun
-- ----------------------------
DROP TABLE IF EXISTS `cc_tts_aliyun`;
CREATE TABLE `cc_tts_aliyun` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `voice_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'tts发音人名称',
  `voice_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'tts发音人代码',
  `voice_enabled` int NOT NULL DEFAULT '1' COMMENT '是否启用',
  `voice_source` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'aliyun_tts' COMMENT '声音源,aliyun_tts、aliyun_tts_flow',
  `priority` int DEFAULT '1' COMMENT 'Display priority. The smaller the number, the more forward it is displayed',
  `provider` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'aliyun' COMMENT 'aliyun、doubao、microsoft',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=550 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='阿里云音色列表';

